package be.schaubroeck.lpb.rkm.rekenmotor.results;

import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelManager;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorDataManagerFactory;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorResultaatHandler;
import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.ControlesRekenResultatenService;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ArtikelLoonElementManagerFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenFeedback;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.service.ControleAgendaService;
import be.schaubroeck.lpb.tools.service.MaandTotaalService;
import be.schaubroeck.lpb.tools.service.RegulAgendaService;
import be.schaubroeck.lpb.tools.service.RekenResultatenService;
import be.schaubroeck.lpb.tools.service.WachtAgendaService;
import com.google.common.collect.ImmutableSet;

import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class BerekenNettoFiscaalVorigJaarResultaatHandlerImpl extends MaandtotaalResultaatHandlerImp {

    private static final Set<RekenBedragType> BV_RELATED_BEDRAGTYPES = ImmutableSet.of(
            RekenBedragType.BEDRIJFSVOORHEFFING,
            RekenBedragType.BEDRIJFSVOORHEFFING_ACHTERSTAL,
            RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_A,
            RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_B,
            RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_INHOUDINGEN,
            RekenBedragType.VLAAMSE_VERMINDERING_BEDRIJFSVOORHEFFING);


    public BerekenNettoFiscaalVorigJaarResultaatHandlerImpl(
            RekenResultatenService rekenResultatenService, MaandTotaalService maandTotaalService,
            WachtAgendaService wachtAgendaService, RegulAgendaService regulAgendaService, ArtikelMotorService artikelMotorService,
            ArtikelMotorResultaatHandler artikelHandler, ArtikelLoonElementManagerFactory artikelLoonElementManagerFactory,
            ArtikelMotorDataManagerFactory artikelMotorDataManagerFactory, ArtikelManager artikelManager, ControleAgendaService controleAgendaService,
            ControlesRekenResultatenService controlesRekenResultatenService, NlpGlobalService nlpGlobalService) {
        super(rekenResultatenService, maandTotaalService, wachtAgendaService, regulAgendaService,
                artikelMotorService, artikelHandler, artikelLoonElementManagerFactory, artikelMotorDataManagerFactory, artikelManager,
                controleAgendaService, controlesRekenResultatenService, nlpGlobalService);
    }

    @Override
    protected void persisteerRekenResultaten(Admin admin, List<RekenHoofd> outputs, List<RekenHoofd> bestaanden, RekenFeedback feedback) {
        outputs = filterResultatenOpCodesEnAard(outputs);
        super.persisteerRekenResultaten(admin, outputs, bestaanden, feedback);
    }


    private List<RekenHoofd> filterResultatenOpCodesEnAard(List<RekenHoofd> outputs) {
        outputs.forEach(rekenHoofd -> rekenHoofd.setRekenLijnen(filterRekenLijnenOp(rekenHoofd)));
        return outputs.stream()
                .filter(rekenHoofd -> !rekenHoofd.getRekenLijnen().isEmpty())
                .collect(Collectors.toList());
    }

    private Set<RekenLijn> filterRekenLijnenOp(RekenHoofd rekenHoofd) {
        return rekenHoofd.getRekenLijnen().stream()
                .filter(this::heeftGeenBvGerelateerdeBedragen)
                .collect(Collectors.toSet());
    }

    private boolean heeftGeenBvGerelateerdeBedragen(RekenLijn rekenLijn) {
        return rekenLijn.getRekenBedragen().stream().noneMatch(this::isBvRelatedBedragType);
    }

    private boolean isBvRelatedBedragType(RekenBedrag rekenBedrag) {
        return BV_RELATED_BEDRAGTYPES.contains(rekenBedrag.getBedragType());
    }
}
